587 VPSingleDefRecipe *vputils::findHeaderMask(VPlan &Plan) {
588   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
589   SmallVector<VPValue *> WideCanonicalIVs;
590   auto *FoundWidenCanonicalIVUser = find_if(
591       LoopRegion->getCanonicalIV()->users(), IsaPred<VPWidenCanonicalIVRecipe>);
592   assert(count_if(LoopRegion->getCanonicalIV()->users(),
593                   IsaPred<VPWidenCanonicalIVRecipe>) <= 1 &&
594          "Must have at most one VPWideCanonicalIVRecipe");
595   if (FoundWidenCanonicalIVUser !=
596       LoopRegion->getCanonicalIV()->users().end()) {
597     auto *WideCanonicalIV =
598         cast<VPWidenCanonicalIVRecipe>(*FoundWidenCanonicalIVUser);
599     WideCanonicalIVs.push_back(WideCanonicalIV);
600   }
601 
602   // Also include VPWidenIntOrFpInductionRecipes that represent a widened
603   // version of the canonical induction.
604   VPBasicBlock *HeaderVPBB = LoopRegion->getEntryBasicBlock();
605   for (VPRecipeBase &Phi : HeaderVPBB->phis()) {
606     auto *WidenOriginalIV = dyn_cast<VPWidenIntOrFpInductionRecipe>(&Phi);
607     if (WidenOriginalIV && WidenOriginalIV->isCanonical())
608       WideCanonicalIVs.push_back(WidenOriginalIV);
609   }
610 
611   // Walk users of wide canonical IVs and find the single compare of the form
612   // (ICMP_ULE, WideCanonicalIV, backedge-taken-count).
613   VPSingleDefRecipe *HeaderMask = nullptr;
614   for (auto *Wide : WideCanonicalIVs) {
615     for (VPUser *U : Wide->users()) {
616       auto *VPI = dyn_cast<VPInstruction>(U);
617       if (!VPI || !vputils::isHeaderMask(VPI, Plan))
618         continue;
619 
620       assert(VPI->getOperand(0) == Wide &&
621              "WidenCanonicalIV must be the first operand of the compare");
622       assert(!HeaderMask && "Multiple header masks found?");
623       HeaderMask = VPI;
624     }
625   }
626   return HeaderMask;
627 }
