647                            const VPDominatorTree &VPDT) {
648   // A latch has a header as its second successor, with its other successor
649   // leaving the loop. A preheader OTOH has a header as its first (and only)
650   // successor.
651   return VPB->getNumSuccessors() == 2 &&
652          VPBlockUtils::isHeader(VPB->getSuccessors()[1], VPDT);
