 982 /// Intrinsic matchers.
 983 struct IntrinsicID_match {
 984   unsigned ID;
 985 
 986   IntrinsicID_match(Intrinsic::ID IntrID) : ID(IntrID) {}
 987 
 988   template <typename OpTy> bool match(OpTy *V) const {
 989     if (const auto *R = dyn_cast<VPWidenIntrinsicRecipe>(V))
 990       return R->getVectorIntrinsicID() == ID;
 991     if (const auto *R = dyn_cast<VPWidenCallRecipe>(V))
 992       return R->getCalledScalarFunction()->getIntrinsicID() == ID;
 993 
 994     auto MatchCalleeIntrinsic = [&](VPValue *CalleeOp) {
 995       if (!isa<VPIRValue>(CalleeOp))
 996         return false;
 997       auto *F = cast<Function>(CalleeOp->getLiveInIRValue());
 998       return F->getIntrinsicID() == ID;
 999     };
1000     if (const auto *R = dyn_cast<VPReplicateRecipe>(V))
1001       if (R->getOpcode() == Instruction::Call) {
1002         // The mask is always the last operand if predicated.
1003         return MatchCalleeIntrinsic(
1004             R->getOperand(R->getNumOperands() - 1 - R->isPredicated()));
1005       }
1006     if (const auto *R = dyn_cast<VPInstruction>(V))
1007       if (R->getOpcode() == Instruction::Call)
1008         return MatchCalleeIntrinsic(R->getOperand(R->getNumOperands() - 1));
1009     return false;
1010   }
1011 };
