1075 /// Match a GEP recipe (VPWidenGEPRecipe, VPInstruction, or VPReplicateRecipe)
1076 /// and bind the source element type and operands.
1077 struct GetElementPtr_match {
1078   Type *&SourceElementType;
1079   ArrayRef<VPValue *> &Operands;
1080 
1081   GetElementPtr_match(Type *&SourceElementType, ArrayRef<VPValue *> &Operands)
1082       : SourceElementType(SourceElementType), Operands(Operands) {}
1083 
1084   template <typename ITy> bool match(ITy *V) const {
1085     return matchRecipeAndBind<VPWidenGEPRecipe>(V) ||
1086            matchRecipeAndBind<VPInstruction>(V) ||
1087            matchRecipeAndBind<VPReplicateRecipe>(V);
1088   }
1089 
1090 private:
1091   template <typename RecipeTy> bool matchRecipeAndBind(const VPValue *V) const {
1092     auto *DefR = dyn_cast<RecipeTy>(V);
1093     if (!DefR)
1094       return false;
1095 
1096     if constexpr (std::is_same_v<RecipeTy, VPWidenGEPRecipe>) {
1097       SourceElementType = DefR->getSourceElementType();
1098     } else if (DefR->getOpcode() == Instruction::GetElementPtr) {
1099       SourceElementType = cast<GetElementPtrInst>(DefR->getUnderlyingInstr())
1100                               ->getSourceElementType();
1101     } else if constexpr (std::is_same_v<RecipeTy, VPInstruction>) {
1102       if (DefR->getOpcode() == VPInstruction::PtrAdd) {
1103         // PtrAdd is a byte-offset GEP with i8 element type.
1104         LLVMContext &Ctx = DefR->getParent()->getPlan()->getContext();
1105         SourceElementType = Type::getInt8Ty(Ctx);
1106       } else {
1107         return false;
1108       }
1109     } else {
1110       return false;
1111     }
1112 
1113     Operands = ArrayRef<VPValue *>(DefR->op_begin(), DefR->op_end());
1114     return true;
1115   }
1116 };
1117 
