4219   //   EMIT vp<%combined> = logical-or vp<%cond.0>, vp<%cond.1>, vp<%cond.2>
4220   //   ...
4221   //
4222   // vector.early.exit.check:
4223   //   EMIT vp<%first.lane> = first-active-lane vp<%combined>
4224   //   EMIT vp<%at.cond.0> = extract-lane vp<%first.lane>, vp<%cond.0>
4225   //   EMIT branch-on-cond vp<%at.cond.0>
4226   // Successor(s): vector.early.exit.0, vector.early.exit.check.0
4227   //
4228   // vector.early.exit.check.0:
4229   //   EMIT vp<%at.cond.1> = extract-lane vp<%first.lane>, vp<%cond.1>
4230   //   EMIT branch-on-cond vp<%at.cond.1>
4231   // Successor(s): vector.early.exit.1, vector.early.exit.2
4232   VPBasicBlock *CurrentBB = DispatchVPBB;
4233   for (auto [I, Exit] : enumerate(ArrayRef(Exits).drop_back())) {
4234     VPValue *LaneVal = DispatchBuilder.createNaryOp(
4235         VPInstruction::ExtractLane, {FirstActiveLane, Exit.CondToExit},
4236         DebugLoc::getUnknown(), "exit.cond.at.lane");
4237 
4238     // For the last dispatch, branch directly to the last exit on false;
4239     // otherwise, create a new check block.
4240     bool IsLastDispatch = (I + 2 == Exits.size());
4241     VPBasicBlock *FalseBB =
4242         IsLastDispatch ? VectorEarlyExitVPBBs.back()
4243                        : Plan.createVPBasicBlock(
4244                              Twine("vector.early.exit.check.") + Twine(I));
4245 
4246     DispatchBuilder.createNaryOp(VPInstruction::BranchOnCond, {LaneVal});
4247     CurrentBB->setSuccessors({VectorEarlyExitVPBBs[I], FalseBB});
4248     VectorEarlyExitVPBBs[I]->setPredecessors({CurrentBB});
4249     FalseBB->setPredecessors({CurrentBB});
4250 
4251     CurrentBB = FalseBB;
4252     DispatchBuilder.setInsertPoint(CurrentBB);
4253   }
4254 
4255   // Replace the latch terminator with the new branching logic.
4256   auto *LatchExitingBranch = cast<VPInstruction>(LatchVPBB->getTerminator());
4257   assert(LatchExitingBranch->getOpcode() == VPInstruction::BranchOnCount &&
4258          "Unexpected terminator");
4259   auto *IsLatchExitTaken =
4260       Builder.createICmp(CmpInst::ICMP_EQ, LatchExitingBranch->getOperand(0),
4261                          LatchExitingBranch->getOperand(1));
4262 
4263   DebugLoc LatchDL = LatchExitingBranch->getDebugLoc();
4264   LatchExitingBranch->eraseFromParent();
4265   Builder.setInsertPoint(LatchVPBB);
4266   Builder.createNaryOp(VPInstruction::BranchOnTwoConds,
4267                        {IsAnyExitTaken, IsLatchExitTaken}, LatchDL);
4268   LatchVPBB->clearSuccessors();
4269   LatchVPBB->setSuccessors({DispatchVPBB, MiddleVPBB, HeaderVPBB});
4270   DispatchVPBB->setPredecessors({LatchVPBB});
