4273 /// This function tries convert extended in-loop reductions to
4274 /// VPExpressionRecipe and clamp the \p Range if it is beneficial and
4275 /// valid. The created recipe must be decomposed to its constituent
4276 /// recipes before execution.
4277 static VPExpressionRecipe *
4278 tryToMatchAndCreateExtendedReduction(VPReductionRecipe *Red, VPCostContext &Ctx,
4279                                      VFRange &Range) {
4280   Type *RedTy = Ctx.Types.inferScalarType(Red);
4281   VPValue *VecOp = Red->getVecOp();
4282 
4283   // Clamp the range if using extended-reduction is profitable.
4284   auto IsExtendedRedValidAndClampRange =
4285       [&](unsigned Opcode, Instruction::CastOps ExtOpc, Type *SrcTy) -> bool {
4286     return LoopVectorizationPlanner::getDecisionAndClampRange(
4287         [&](ElementCount VF) {
4288           auto *SrcVecTy = cast<VectorType>(toVectorTy(SrcTy, VF));
4289           TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput;
4290 
4291           InstructionCost ExtRedCost = InstructionCost::getInvalid();
4292           InstructionCost ExtCost =
4293               cast<VPWidenCastRecipe>(VecOp)->computeCost(VF, Ctx);
4294           InstructionCost RedCost = Red->computeCost(VF, Ctx);
4295 
4296           if (Red->isPartialReduction()) {
4297             TargetTransformInfo::PartialReductionExtendKind ExtKind =
4298                 TargetTransformInfo::getPartialReductionExtendKind(ExtOpc);
4299             // FIXME: Move partial reduction creation, costing and clamping
4300             // here from LoopVectorize.cpp.
4301             ExtRedCost = Ctx.TTI.getPartialReductionCost(
4302                 Opcode, SrcTy, nullptr, RedTy, VF, ExtKind,
4303                 llvm::TargetTransformInfo::PR_None, std::nullopt, Ctx.CostKind,
4304                 RedTy->isFloatingPointTy()
4305                     ? std::optional{Red->getFastMathFlags()}
4306                     : std::nullopt);
4307           } else if (!RedTy->isFloatingPointTy()) {
4308             // TTI::getExtendedReductionCost only supports integer types.
4309             ExtRedCost = Ctx.TTI.getExtendedReductionCost(
4310                 Opcode, ExtOpc == Instruction::CastOps::ZExt, RedTy, SrcVecTy,
4311                 Red->getFastMathFlags(), CostKind);
4312           }
4313           return ExtRedCost.isValid() && ExtRedCost < ExtCost + RedCost;
4314         },
4315         Range);
4316   };
4317 
4318   VPValue *A;
4319   // Match reduce(ext)).
4320   if (isa<VPWidenCastRecipe>(VecOp) &&
4321       (match(VecOp, m_ZExtOrSExt(m_VPValue(A))) ||
4322        match(VecOp, m_FPExt(m_VPValue(A)))) &&
4323       IsExtendedRedValidAndClampRange(
4324           RecurrenceDescriptor::getOpcode(Red->getRecurrenceKind()),
4325           cast<VPWidenCastRecipe>(VecOp)->getOpcode(),
4326           Ctx.Types.inferScalarType(A)))
4327     return new VPExpressionRecipe(cast<VPWidenCastRecipe>(VecOp), Red);
4328 
4329   return nullptr;
